import{_ as e,c as s,a as i,o as n}from"./app-CEcM0piI.js";const p={};function t(r,a){return n(),s("div",null,a[0]||(a[0]=[i(`<h2 id="类-class-和实例-instance" tabindex="-1"><a class="header-anchor" href="#类-class-和实例-instance"><span>类（class）和实例（instance）</span></a></h2><h3 id="使用" tabindex="-1"><a class="header-anchor" href="#使用"><span>使用</span></a></h3><p>使用class关键字定义一个类，类名的首字母要大写</p><p>当程序员需要创建的类型不能用简单类型表示时就需要创建类</p><p>类把需要的变量和函数组合在一起，这种包含也称之为封装</p><h3 id="结构" tabindex="-1"><a class="header-anchor" href="#结构"><span>结构</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>class 类名:</span></span>
<span class="line"><span>    成员变量</span></span>
<span class="line"><span>    成员函数</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="定义" tabindex="-1"><a class="header-anchor" href="#定义"><span>定义</span></a></h3><p>类</p><p>分类，把所有事物抽象成类，属性相同的放入一个类中是面向对象编程的重要思想</p><p>对象 对象就是类中的一个具体实例</p><p>self 它指向类本身，包含这个类本身所有的属性和方法</p><p>object 传入的实例对象</p><p><code>__init__</code> 定义初始值 初始化类，成员变量可以任意定义，获取该变量时需：class.variable()</p><h3 id="封装encapsulation" tabindex="-1"><a class="header-anchor" href="#封装encapsulation"><span>封装encapsulation</span></a></h3><p>对外部世界隐藏对象的工作细节</p><h3 id="继承inheritance和多态polymorphism" tabindex="-1"><a class="header-anchor" href="#继承inheritance和多态polymorphism"><span>继承inheritance和多态polymorphism</span></a></h3><p>继承</p><p>继承使子类具有父类的各种属性和方法，而不需要编写相同的代码</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>class2(class1)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>类2继承于类1</p><p>类1是类2的父类，类2是类1的子类，不能是毫不相干的两个类。如车和跑车这两个类就可以</p><p>多态</p><p>为不同的数据类型的实体提供统一的接口</p><p>定义父类的一个方法，其他子类无需定义只要继承即可使用，使函数调用和代码类型更加方便。相当于车都能跑，但每类车的用途不一样，跑车跑的快，货车能装更多东西。</p><h3 id="访问限制" tabindex="-1"><a class="header-anchor" href="#访问限制"><span>访问限制</span></a></h3><p>出于安全等因素的考虑，限制其他人访问自己定义的类可在属性名字前加两个下划线，这样在调用该属性时会返回error</p><h3 id="补充" tabindex="-1"><a class="header-anchor" href="#补充"><span>补充</span></a></h3><p>如果想要定义的类能被for循环遍历，需要定义__iter__和__next__</p>`,29)]))}const d=e(p,[["render",t]]),c=JSON.parse('{"path":"/python/python/5/","title":"5 类和实例","lang":"zh-CN","frontmatter":{"title":"5 类和实例","createTime":"2025/04/05 12:12:26","permalink":"/python/python/5/"},"readingTime":{"minutes":1.61,"words":484},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/Python/python/5 类和实例.md","headers":[]}');export{d as comp,c as data};
